import{_ as a,c as e,o as l,V as i}from"./chunks/framework.9b555ede.js";const _=JSON.parse('{"title":"mini-vue","description":"","frontmatter":{},"headers":[],"relativePath":"original/【开发】手写vue2.x源码.md","filePath":"original/【开发】手写vue2.x源码.md","lastUpdated":1640536454000}'),s={name:"original/【开发】手写vue2.x源码.md"},t=i('<h1 id="mini-vue" tabindex="-1">mini-vue <a class="header-anchor" href="#mini-vue" aria-label="Permalink to &quot;mini-vue&quot;">​</a></h1><hr><p><a href="https://github.com/nkxrb/mini-vue" target="_blank" rel="noreferrer">源码仓库地址</a></p><p>从零开始，一步一步实现vue。和网络上其他的源码解析不同，我们换一个角度，用我们最熟悉最简单的方式，一步一步推演vue框架的诞生。</p><p>对于大多数人来说，一上来看源码，一点用处也没有。照着源码敲，也无法真正领悟其中的精髓，无法学以致用。只有自己亲自上手，才会发现差距。</p><p>因此，我创建了这个仓库，以最原始的方式慢慢推演出Vue。每个版本对应一个分支，从v0.0.1开始，每个版本对应一个小功能。</p><p>PS：在编码过程中，为了更清晰的了解逻辑，会省略一些数据校验，我们都假设为正确的数据。（不必细究）</p><h2 id="vue功能点" tabindex="-1">Vue功能点 <a class="header-anchor" href="#vue功能点" aria-label="Permalink to &quot;Vue功能点&quot;">​</a></h2><ul><li>模板解析，生成数据对象与render函数</li><li>数据响应式 （监听器与依赖收集）</li><li>执行render生成虚拟DOM，diff算法更新虚拟DOM</li><li>v-model,v-for,v-if,v-show...等指令</li><li>自定义指令</li><li>mixin</li><li>props,computed</li><li>生命周期钩子</li><li>事件管理机制</li></ul><h2 id="安装、启动" tabindex="-1">安装、启动 <a class="header-anchor" href="#安装、启动" aria-label="Permalink to &quot;安装、启动&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">pnpm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">i</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">npm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">run</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">dev</span></span></code></pre></div><h2 id="简单应用场景" tabindex="-1">简单应用场景 <a class="header-anchor" href="#简单应用场景" aria-label="Permalink to &quot;简单应用场景&quot;">​</a></h2><p>一个按钮，一个数字，不断点击按钮，数字对应的变化</p><h2 id="v0-0-1" tabindex="-1">v0.0.1 <a class="header-anchor" href="#v0-0-1" aria-label="Permalink to &quot;v0.0.1&quot;">​</a></h2><p>简单的单文件vue.js 通过Object.defineProperty 改变dom</p><h2 id="v0-0-2" tabindex="-1">v0.0.2 <a class="header-anchor" href="#v0-0-2" aria-label="Permalink to &quot;v0.0.2&quot;">​</a></h2><p>模块化改造，将单个vue文件拆解成多个文件。 重点探究vue的响应式依赖收集原理，其他的功能就简化了</p><ul><li>app.js 组件对象抽离，render函数需要重新设计</li><li>abserver.js 响应式逻辑抽离，需要考虑依赖收集与更新的操作时机。</li><li>dep 与 watcher 之间的多对多关系映射，以及对Dep.target对象的理解</li></ul><h2 id="v0-0-3" tabindex="-1">v0.0.3 <a class="header-anchor" href="#v0-0-3" aria-label="Permalink to &quot;v0.0.3&quot;">​</a></h2><p>实现虚拟DOM渲染</p><p>重点探究子节点更新的diff算法，以及DOM更新渲染的判断逻辑</p><ul><li>新旧数组，分别使用双指针进行遍历</li><li>判断顺序：旧前-新前, 旧后-新后, 旧前-新后, 旧后-新前, 新前依次查找匹配（优先使用key匹配）</li><li>重点关注每个vnode的el属性，确保el不遗失</li></ul>',23),n=[t];function r(o,p,c,d,h,u){return l(),e("div",null,n)}const m=a(s,[["render",r]]);export{_ as __pageData,m as default};
